import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Helmet } from 'react-helmet-async';
import { motion, AnimatePresence } from 'framer-motion';
import { supabase } from '../config/supabase';
import { useAuth } from '../contexts/AuthContext';
import VoteButtons from '../components/voting/VoteButtons';
import { formatDistanceToNow } from 'date-fns';
import { fr } from 'date-fns/locale';

const PROPOSALS_PER_PAGE = 10;

const Proposals = () => {
  const { t } = useTranslation();
  const { isAuthenticated, user } = useAuth();
  
  const [proposals, setProposals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [totalCount, setTotalCount] = useState(0);
  
  const [filter, setFilter] = useState('all'); // all, yes, no
  const [sort, setSort] = useState('recent'); // recent, popular, controversial
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedProvince, setSelectedProvince] = useState('');

  const fetchProposals = useCallback(async (pageNum = 1, reset = false) => {
    setLoading(true);
    
    try {
      let query = supabase
        .from('proposals')
        .select(`
          *,
          profile:profiles!proposals_user_id_fkey(
            id,
            first_name,
            last_name,
            portrait_url,
            province,
            profession
          )
        `, { count: 'exact' })
        .eq('status', 'published');

      // Apply filters
      if (filter === 'yes') {
        query = query.gt('yes_count', 0);
      } else if (filter === 'no') {
        query = query.gt('no_count', 0);
      }

      if (selectedProvince) {
        query = query.eq('profiles.province', selectedProvince);
      }

      if (searchTerm) {
        query = query.or(
          `subject.ilike.%${searchTerm}%,content.ilike.%${searchTerm}%,one_sentence.ilike.%${searchTerm}%`
        );
      }

      // Apply sorting
      switch (sort) {
        case 'popular':
          query = query.order('yes_count', { ascending: false });
          break;
        case 'controversial':
          query = query.order('total_votes', { ascending: false });
          break;
        case 'recent':
        default:
          query = query.order('created_at', { ascending: false });
          break;
      }

      // Pagination
      const from = (pageNum - 1) * PROPOSALS_PER_PAGE;
      const to = from + PROPOSALS_PER_PAGE - 1;

      const { data, error, count } = await query.range(from, to);

      if (error) throw error;

      // Transform data
      const transformedData = data?.map(proposal => ({
        ...proposal,
        total_votes: (proposal.yes_count || 0) + (proposal.no_count || 0),
        yes_percentage: ((proposal.yes_count || 0) + (proposal.no_count || 0)) > 0
          ? Math.round((proposal.yes_count / ((proposal.yes_count || 0) + (proposal.no_count || 0))) * 100)
          : 0,
        no_percentage: ((proposal.yes_count || 0) + (proposal.no_count || 0)) > 0
          ? Math.round((proposal.no_count / ((proposal.yes_count || 0) + (proposal.no_count || 0))) * 100)
          : 0,
        time_ago: formatDistanceToNow(new Date(proposal.created_at), { 
          addSuffix: true, 
          locale: fr 
        })
      })) || [];

      if (reset) {
        setProposals(transformedData);
      } else {
        setProposals(prev => [...prev, ...transformedData]);
      }

      setTotalCount(count || 0);
      setHasMore(count > to + 1);
      setPage(pageNum);
    } catch (error) {
      console.error('Error fetching proposals:', error);
    } finally {
      setLoading(false);
    }
  }, [filter, sort, searchTerm, selectedProvince]);

  // Fetch on mount and when filters change
  useEffect(() => {
    fetchProposals(1, true);
  }, [filter, sort, searchTerm, selectedProvince]);

  // Load more
  const loadMore = () => {
    if (!loading && hasMore) {
      fetchProposals(page + 1);
    }
  };

  // Handle vote update
  const handleVoteUpdate = (proposalId, voteType) => {
    setProposals(prev => prev.map(p => {
      if (p.id === proposalId) {
        const updatedYes = voteType === 'yes' ? (p.yes_count + 1) : p.yes_count;
        const updatedNo = voteType === 'no' ? (p.no_count + 1) : p.no_count;
        const totalVotes = updatedYes + updatedNo;
        
        return {
          ...p,
          yes_count: updatedYes,
          no_count: updatedNo,
          total_votes: totalVotes,
          yes_percentage: totalVotes > 0 ? Math.round((updatedYes / totalVotes) * 100) : 0,
          no_percentage: totalVotes > 0 ? Math.round((updatedNo / totalVotes) * 100) : 0
        };
      }
      return p;
    }));
  };

  // Province list
  const provinces = [
    'Kinshasa', 'Nord-Kivu', 'Sud-Kivu', 'Ituri', 'Haut-UĂ©lĂ©',
    'Tshopo', 'Bas-UĂ©lĂ©', 'Ă‰quateur', 'Sud-Ubangi', 'Nord-Ubangi',
    'Mongala', 'Tshuapa', 'Maniema', 'KasaĂŻ', 'KasaĂŻ-Central',
    'KasaĂŻ-Oriental', 'Lomami', 'Sankuru', 'Tanganyika', 'Haut-Lomami',
    'Lualaba', 'Haut-Katanga', 'Kwango', 'Kwilu', 'Mai-Ndombe', 'Kongo Central'
  ];

  return (
    <>
      <Helmet>
        <title>Propositions Citoyennes | MAONI v100.04</title>
        <meta name="description" content="Consultez et votez sur les propositions de rĂ©forme constitutionnelle en RDC" />
      </Helmet>

      <div className="container" style={{ paddingTop: 'var(--space-2xl)', paddingBottom: 'var(--space-3xl)' }}>
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          style={{ marginBottom: 'var(--space-2xl)' }}
        >
          <h1 style={{ 
            color: 'var(--drc-blue)', 
            fontFamily: 'var(--font-display)',
            textAlign: 'center',
            marginBottom: 'var(--space-sm)'
          }}>
            đź“‹ {t('proposals.title')}
          </h1>
          <p style={{ 
            textAlign: 'center', 
            color: 'var(--gray-600)',
            fontSize: '1.1rem'
          }}>
            {totalCount} propositions soumises par les citoyens
          </p>
        </motion.div>

        {/* Filters Bar */}
        <div style={{
          display: 'flex',
          flexWrap: 'wrap',
          gap: 'var(--space-md)',
          marginBottom: 'var(--space-xl)',
          padding: 'var(--space-lg)',
          background: 'white',
          borderRadius: 'var(--radius-xl)',
          boxShadow: 'var(--shadow-md)',
          alignItems: 'center'
        }}>
          {/* Search */}
          <div style={{ flex: '1', minWidth: '200px' }}>
            <input
              type="text"
              placeholder="đź”Ť Rechercher une proposition..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="form-input"
              style={{ margin: 0 }}
            />
          </div>

          {/* Province Filter */}
          <select
            value={selectedProvince}
            onChange={(e) => setSelectedProvince(e.target.value)}
            className="form-select"
            style={{ width: 'auto', margin: 0 }}
          >
            <option value="">Toutes les provinces</option>
            {provinces.map(p => (
              <option key={p} value={p}>{p}</option>
            ))}
          </select>

          {/* Vote Filter */}
          <div style={{ display: 'flex', gap: 'var(--space-sm)' }}>
            <button
              className={`btn btn-sm ${filter === 'all' ? 'btn-primary' : ''}`}
              onClick={() => setFilter('all')}
              style={filter !== 'all' ? { background: 'var(--gray-100)', color: 'var(--gray-700)' } : {}}
            >
              {t('proposals.filter.all')}
            </button>
            <button
              className={`btn btn-sm ${filter === 'yes' ? 'btn-primary' : ''}`}
              onClick={() => setFilter('yes')}
              style={filter !== 'yes' ? { 
                background: '#f0fdf4', 
                color: 'var(--success)',
                border: '1px solid var(--success)'
              } : {}}
            >
              âś… {t('proposals.filter.yes')}
            </button>
            <button
              className={`btn btn-sm ${filter === 'no' ? 'btn-primary' : ''}`}
              onClick={() => setFilter('no')}
              style={filter !== 'no' ? { 
                background: '#fef2f2', 
                color: 'var(--error)',
                border: '1px solid var(--error)'
              } : {}}
            >
              âťŚ {t('proposals.filter.no')}
            </button>
          </div>

          {/* Sort */}
          <select
            value={sort}
            onChange={(e) => setSort(e.target.value)}
            className="form-select"
            style={{ width: 'auto', margin: 0 }}
          >
            <option value="recent">{t('proposals.sort.recent')}</option>
            <option value="popular">{t('proposals.sort.popular')}</option>
            <option value="controversial">{t('proposals.sort.controversial')}</option>
          </select>

          {/* Submit Button */}
          {isAuthenticated && (
            <Link to="/submit-proposal" className="btn btn-primary btn-sm">
              âśŤď¸Ź {t('proposals.submit')}
            </Link>
          )}
        </div>

        {/* Proposals Feed */}
        <AnimatePresence>
          <div className="proposals-feed">
            {proposals.map((proposal, index) => (
              <motion.div
                key={proposal.id}
                className={`proposal-card ${
                  proposal.yes_percentage > 50 ? 'majority-yes' : 
                  proposal.no_percentage > 50 ? 'majority-no' : ''
                }`}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.05, duration: 0.4 }}
                whileHover={{ borderLeftColor: 'var(--drc-yellow)' }}
              >
                {/* Header */}
                <div className="proposal-card-header">
                  <img
                    src={proposal.profile?.portrait_url || '/images/default-avatar.png'}
                    alt={proposal.profile?.first_name}
                    className="proposal-card-avatar"
                  />
                  <div className="proposal-card-user">
                    <div className="proposal-card-name">
                      {proposal.profile?.first_name} {proposal.profile?.last_name}
                    </div>
                    <div className="proposal-card-date">
                      {proposal.time_ago}
                    </div>
                  </div>
                  {proposal.profile?.province && (
                    <span className="proposal-card-province-badge">
                      đź“Ť {proposal.profile.province}
                    </span>
                  )}
                </div>

                {/* Content */}
                <Link 
                  to={`/proposals/${proposal.id}`}
                  style={{ textDecoration: 'none', color: 'inherit' }}
                >
                  <h3 className="proposal-card-subject">
                    {proposal.subject}
                  </h3>
                  <p className="proposal-card-summary">
                    đź’ˇ {proposal.one_sentence}
                  </p>
                  <p className="proposal-card-content">
                    {proposal.content?.substring(0, 300)}
                    {proposal.content?.length > 300 && '...'}
                  </p>
                </Link>

                {/* Images Preview */}
                {proposal.image_urls && proposal.image_urls.length > 0 && (
                  <div className="proposal-card-images">
                    <div className="proposal-image-grid">
                      {proposal.image_urls.slice(0, 3).map((url, i) => (
                        <div key={i} className="proposal-image-container">
                          <img src={url} alt={`Image ${i + 1}`} className="proposal-image" />
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Voting Section */}
                <div className="proposal-card-actions">
                  {isAuthenticated ? (
                    <VoteButtons 
                      proposalId={proposal.id}
                      yesCount={proposal.yes_count}
                      noCount={proposal.no_count}
                      userId={user?.id}
                      onVoteUpdate={handleVoteUpdate}
                    />
                  ) : (
                    <Link to="/login" className="btn btn-sm" style={{
                      background: 'var(--gray-100)',
                      color: 'var(--gray-700)'
                    }}>
                      Connectez-vous pour voter
                    </Link>
                  )}

                  {/* Vote Bar */}
                  <div style={{ flex: 1, minWidth: '150px' }}>
                    <div style={{ 
                      display: 'flex', 
                      justifyContent: 'space-between', 
                      marginBottom: '0.25rem',
                      fontSize: '0.85rem'
                    }}>
                      <span style={{ color: 'var(--success)', fontWeight: 600 }}>
                        OUI {proposal.yes_percentage}%
                      </span>
                      <span style={{ color: 'var(--error)', fontWeight: 600 }}>
                        NON {proposal.no_percentage}%
                      </span>
                    </div>
                    <div className="vote-bar">
                      <div 
                        className="vote-bar-yes" 
                        style={{ width: `${proposal.yes_percentage}%` }}
                      />
                      <div 
                        className="vote-bar-no" 
                        style={{ width: `${proposal.no_percentage}%` }}
                      />
                    </div>
                    <div style={{ 
                      textAlign: 'center', 
                      marginTop: '0.25rem',
                      fontSize: '0.8rem',
                      color: 'var(--gray-500)'
                    }}>
                      {proposal.total_votes} votes
                    </div>
                  </div>

                  {/* View Details */}
                  <Link 
                    to={`/proposals/${proposal.id}`}
                    className="btn btn-sm"
                    style={{
                      background: 'var(--gray-100)',
                      color: 'var(--gray-700)'
                    }}
                  >
                    DĂ©tails â†’
                  </Link>
                </div>
              </motion.div>
            ))}
          </div>
        </AnimatePresence>

        {/* Loading State */}
        {loading && (
          <div style={{ textAlign: 'center', padding: 'var(--space-xl)' }}>
            <div className="loading-spinner" />
            <p style={{ color: 'var(--gray-500)', marginTop: 'var(--space-md)' }}>
              Chargement des propositions...
            </p>
          </div>
        )}

        {/* Load More Button */}
        {hasMore && !loading && (
          <div style={{ textAlign: 'center', marginTop: 'var(--space-xl)' }}>
            <motion.button
              className="btn btn-primary btn-lg"
              onClick={loadMore}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              đź“Ą Charger plus de propositions
            </motion.button>
          </div>
        )}

        {/* Empty State */}
        {!loading && proposals.length === 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            style={{ 
              textAlign: 'center', 
              padding: 'var(--space-3xl)',
              color: 'var(--gray-500)'
            }}
          >
            <div style={{ fontSize: '4rem', marginBottom: 'var(--space-md)' }}>
              đź“­
            </div>
            <h3>Aucune proposition trouvĂ©e</h3>
            <p>
              {searchTerm 
                ? 'Essayez de modifier vos critĂ¨res de recherche.'
                : 'Soyez le premier Ă  soumettre une proposition !'}
            </p>
            {isAuthenticated && (
              <Link to="/submit-proposal" className="btn btn-primary" style={{ marginTop: 'var(--space-md)' }}>
                âśŤď¸Ź Soumettre une proposition
              </Link>
            )}
          </motion.div>
        )}

        {/* Total Count */}
        <div style={{ 
          textAlign: 'center', 
          marginTop: 'var(--space-xl)',
          color: 'var(--gray-500)',
          fontSize: '0.9rem'
        }}>
          Affichage de {proposals.length} sur {totalCount} propositions
        </div>
      </div>
    </>
  );
};

export default Proposals;
